    // dp[i][0]: maximum score of a valid alternating subsequence ending at index i, 
    // where nums[i] is expected to be smaller than the previous element (i.e., the sequence ends with a 'peak' if length > 1, or just starts)
    // For the first element (length 1), both states are valid.
    // We define:
    // dp[i][0]: Max score ending at i, where the required transition is nums[j] > nums[i] (i.e., current element is a 'valley' or the start)
    // dp[i][1]: Max score ending at i, where the required transition is nums[j] < nums[i] (i.e., current element is a 'peak' or the start)
    // Wait, the alternating property depends on the *previous* element. Let's redefine:

    // dp[i][0]: Max score of a valid sequence ending at index i, where the last transition was 'down' (i.e., nums[prev] > nums[i]).
    // dp[i][1]: Max score of a valid sequence ending at index i, where the last transition was 'up' (i.e., nums[prev] < nums[i]).
    // For length 1, both are effectively valid starts.

    // Let's simplify the state based on the expected *next* transition for easier DP.
    // dp[i][0]: Max score of a valid sequence ending at index i, where the sequence must continue with an element *smaller* than nums[i] next (i.e., nums[i] is a peak or the sequence is of odd length 1, 3, 5...)
    // dp[i][1]: Max score of a valid sequence ending at index i, where the sequence must continue with an element *larger* than nums[i] next (i.e., nums[i] is a valley or the sequence is of even length 0, 2, 4...)

    // A length 1 sequence is both a peak and a valley relative to non-existent neighbors.
    // If length is 1: [a]. Next must be < a OR > a. It can start either way.

    // Let's stick to the transition type:
    // dp[i][0]: Max score ending at i, where the sequence ends with X < nums[i] (i.e., nums[i] is a "peak" or the first element if we consider the start as an implicit valley before it)
    // dp[i][1]: Max score ending at i, where the sequence ends with X > nums[i] (i.e., nums[i] is a "valley" or the first element if we consider the start as an implicit peak before it)

    let mut dp = vec![vec![0i64; 2]; n];
    let mut max_score = 0i64;

    for i in 0..n {
        let current_val = nums[i];

        // Base case: Subsequence of length 1. Score is nums[i].
        // For length 1, it can be considered the end of a 'peak' or a 'valley'.
        dp[i][0] = current_val; // Treat as ending after an "up" transition, so it expects a down transition next (or it's the start)
        dp[i][1] = current_val; // Treat as ending after a "down" transition, so it expects an up transition next (or it's the start)

        for j in 0..i {
            if i as i64 - j as i64 >= k {
                let prev_val = nums[j];

                // Case 1: Transition was UP (prev_val < current_val). 
                // This means the sequence ending at j must have ended with a DOWN transition (dp[j][1]).
                // New state at i ends with an UP transition.
                if prev_val < current_val {
                    // Previous state at j must have been expecting an UP transition (i.e., it was a valley, dp[j][1])
                    dp[i][0] = dp[i][0].max(dp[j][1] + current_val);
                }

                // Case 2: Transition was DOWN (prev_val > current_val).
                // This means the sequence ending at j must have ended with an UP transition (dp[j][0]).
                // New state at i ends with a DOWN transition.
                if prev_val > current_val {
                    // Previous state at j must have been expecting a DOWN transition (i.e., it was a peak, dp[j][0])
                    dp[i][1] = dp[i][1].max(dp[j][0] + current_val);
                }
            }
        }

        max_score = max_score.max(dp[i][0]).max(dp[i][1]);
    }

